import React, { useState, useEffect } from "react";
import MapView from "../components/MapView";
import { io } from "socket.io-client";

const socket = io("http://localhost:5000");

function Journey() {

  const [destination, setDestination] = useState("");
  const [originCoords, setOriginCoords] = useState(null);
  const [destinationCoords, setDestinationCoords] = useState(null);
  const [info, setInfo] = useState(null);
  const [voiceOn, setVoiceOn] = useState(false);

  /* 📍 GET LIVE LOCATION */
  useEffect(() => {
    const watchId = navigator.geolocation.watchPosition(
      (pos) => {
        const lat = pos.coords.latitude;
        const lon = pos.coords.longitude;

        const current = { lat, lng: lon };

        setOriginCoords(current);

        // send to backend
        fetch("http://localhost:5000/location", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ lat, lon }),
        });

        // socket live
        socket.emit("location", { lat, lon });
      },
      (err) => console.log(err),
      { enableHighAccuracy: true }
    );

    return () => navigator.geolocation.clearWatch(watchId);
  }, []);

  /* 🎯 SET DESTINATION (dummy convert) */
  const setDestinationFunc = () => {
    if (!destination) return alert("Enter destination");

    // ⚡ Replace with Google Geocoding later
    setDestinationCoords({
      lat: originCoords?.lat + 0.01,
      lng: originCoords?.lng + 0.01,
    });
  };

  /* 🚀 START TRACKING */
  const startTracking = () => {
    alert("Tracking started 🚀");
  };

  /* 🚨 SOS */
  const triggerEmergency = async () => {
    if (!originCoords) return alert("Location not available");

    await fetch("http://localhost:5000/sos", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        lat: originCoords.lat,
        lon: originCoords.lng,
      }),
    });

    alert("🚨 SOS Sent!");
  };

  /* 🎤 VOICE SOS */
  useEffect(() => {
    if (!voiceOn) return;

    const SpeechRecognition =
      window.SpeechRecognition || window.webkitSpeechRecognition;

    if (!SpeechRecognition) return;

    const recognition = new SpeechRecognition();
    recognition.continuous = true;

    recognition.onresult = (event) => {
      const text =
        event.results[event.results.length - 1][0].transcript.toLowerCase();

      if (text.includes("help me")) {
        triggerEmergency();
      }
    };

    recognition.start();

    return () => recognition.stop();
  }, [voiceOn]);

  return (
    <div className="app">

      {/* HEADER */}
      <div className="header-card">
        <div className="shield">🛡️</div>
        <h2>Women Safety Monitor</h2>
        <p>Real-time journey protection system</p>
      </div>

      {/* FORM */}
      <div className="section-card">

        <h3>Journey Setup</h3>

        <label>Destination *</label>
        <input
          placeholder="Enter your destination"
          value={destination}
          onChange={(e) => setDestination(e.target.value)}
        />

        <p className="sub">Emergency Contact</p>

        <input placeholder="Guardian's full name" />
        <input placeholder="+91 98765 43210" />
        <input placeholder="guardian@email.com" />

        <p className="sub">Voice Recognition</p>
        <input placeholder="help me" />

        <button className="primary-btn" onClick={setDestinationFunc}>
          📍 Set Destination
        </button>

        <button className="primary-btn" onClick={startTracking}>
          ✈ Start Safe Journey
        </button>

      </div>

      {/* MAP */}
      <div className="map-wrap">
        <MapView
          origin={originCoords}
          destination={destinationCoords}
          setInfo={setInfo}
        />
      </div>

      {/* STATUS */}
      <div className="status">

        <div className="status-header">
          🛡 STATUS <span>SAFE</span>
        </div>

        <div className="status-grid">
          <div>
            <p>Journey Time</p>
            <h3>{info?.time || "--"} min</h3>
          </div>

          <div>
            <p>Speed</p>
            <h3>-- km/h</h3>
          </div>
        </div>

        <div className="status-row">
          📍 Current Location <br />
          {originCoords
            ? `${originCoords.lat}, ${originCoords.lng}`
            : "Fetching..."}
        </div>

        <div className="status-row">
          📍 Destination <br />
          {destination || "Not set"}
        </div>

        <div className="alert">
          ⚠ Route deviation: 8.1 km
        </div>

      </div>

      {/* SOS */}
      <div className="sos-section">
        <button className="sos-btn" onClick={triggerEmergency}>
          🚨 SOS EMERGENCY
          <p>Tap to alert contacts & call 112</p>
        </button>
      </div>

      {/* ACTIONS */}
      <div className="actions">

        <button onClick={() => window.open("tel:112")}>
          📞 Call 112
        </button>

        <button
          onClick={() =>
            originCoords &&
            window.open(
              `https://maps.google.com/?q=${originCoords.lat},${originCoords.lng}`
            )
          }
        >
          📤 Share Location
        </button>

        <button onClick={() => setVoiceOn(!voiceOn)}>
          🎤 {voiceOn ? "Voice ON" : "Voice OFF"}
        </button>

        <button>
          🚓 Police Stations
        </button>

      </div>

    </div>
  );
}

export default Journey;
